import{_ as t,o as e,c as r,ag as o,ah as s}from"./chunks/framework.D9bIGSBm.js";const m=JSON.parse('{"title":"集成终端","description":"","frontmatter":{},"headers":[],"relativePath":"features/terminal.md","filePath":"features/terminal.md"}'),n={name:"features/terminal.md"};function l(i,a,h,c,d,p){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="集成终端" tabindex="-1">集成终端 <a class="header-anchor" href="#集成终端" aria-label="Permalink to &quot;集成终端&quot;">​</a></h1><p>集成终端让你无需切换到外部终端工具，直接在 LoongCode 内运行命令行操作。它是真实的 PTY 终端（PTY 即伪终端，是操作系统提供的终端仿真接口，支持交互式程序如 <code>vim</code>、<code>top</code>、<code>npm install</code> 等正常运行）。AI 执行命令时也通过同一终端进行，你可以实时看到输出。</p><hr><h2 id="打开终端" tabindex="-1">打开终端 <a class="header-anchor" href="#打开终端" aria-label="Permalink to &quot;打开终端&quot;">​</a></h2><p><strong>方法一</strong>：点击顶部标题栏的<strong>终端</strong>按钮。</p><p><strong>方法二</strong>：按快捷键 <strong>Ctrl+`</strong>（反引号，Tab 键上方）。</p><p>终端面板从中央对话区底部弹出，覆盖在对话区下方，不影响右侧面板的正常使用。再次点击<strong>终端</strong>按钮或按 Ctrl+` 可关闭面板。</p><p><img src="'+s+'" alt="截图：集成终端面板从对话区底部弹出，显示 Shell 提示符，标题栏中「终端」按钮处于激活状态"></p><hr><h2 id="多标签页管理" tabindex="-1">多标签页管理 <a class="header-anchor" href="#多标签页管理" aria-label="Permalink to &quot;多标签页管理&quot;">​</a></h2><p>终端面板支持同时开启多个终端会话：</p><ul><li>点击面板顶部的<strong>新建终端</strong>按钮（+ 图标），新开一个独立的终端标签页。</li><li>点击标签页右侧的关闭按钮可<strong>单独关闭</strong>该终端，同时结束其子进程树，不影响其他标签页。</li><li>点击面板右上角的<strong>关闭终端面板</strong>按钮，关闭并结束当前工作区的<strong>所有</strong>终端。</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>关闭终端会连同该终端启动的所有子进程一起结束，避免后台进程残留占用目录。</p></div><hr><h2 id="ai-与终端联动" tabindex="-1">AI 与终端联动 <a class="header-anchor" href="#ai-与终端联动" aria-label="Permalink to &quot;AI 与终端联动&quot;">​</a></h2><p>AI（Agent）执行命令时会在当前工作区的终端中运行，你可以实时看到每条命令的完整输出——构建日志、测试结果、安装进度都逐行显示。</p><p>你同样可以在终端里直接输入命令，与 AI 协同工作：比如 AI 写好脚本后，你手动在终端里运行并把结果告诉 AI。</p><hr><h2 id="环境变量" tabindex="-1">环境变量 <a class="header-anchor" href="#环境变量" aria-label="Permalink to &quot;环境变量&quot;">​</a></h2><p>终端继承工作区的环境变量配置。如需添加全局环境变量（对所有任务生效），请前往<strong>设置 → 常规</strong>进行配置；详见<a href="/docs/settings/general.html">设置 → 常规</a>。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>了解终端之后，接下来看看如何管理 Git 分支、提交代码以及审查改动——前往 <a href="/docs/features/git.html">Git 集成</a>继续学习。</p>',23)])])}const u=t(n,[["render",l]]);export{m as __pageData,u as default};
